import React, { useState, useEffect } from 'react';
import 'bootstrap/dist/css/bootstrap.min.css';
import './App.css';
import SentimentForm from './components/SentimentForm';
import ResultDisplay from './components/ResultDisplay';
import HistoryList from './components/HistoryList';
import { Container, Row, Col, Card } from 'react-bootstrap';
import axios from 'axios';

const API_URL = 'http://localhost:5000/api';

function App() {
  const [result, setResult] = useState(null);
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  // Fetch history on component mount
  useEffect(() => {
    fetchHistory();
  }, []);

  const fetchHistory = async () => {
    try {
      const response = await axios.get(`${API_URL}/history`);
      setHistory(response.data);
    } catch (err) {
      console.error('Error fetching history:', err);
      setError('Failed to load history');
    }
  };

  const analyzeSentiment = async (text) => {
    setLoading(true);
    setError('');

    try {
      const response = await axios.post(`${API_URL}/analyze`, { text });
      setResult(response.data);

      // Update history after successful analysis
      fetchHistory();
    } catch (err) {
      console.error('Error analyzing text:', err);
      setError('Failed to analyze text');
    } finally {
      setLoading(false);
    }
  };

  const deleteRecord = async (id) => {
    try {
      await axios.delete(`${API_URL}/history/${id}`);
      // Update history after deletion
      fetchHistory();
    } catch (err) {
      console.error('Error deleting record:', err);
      setError('Failed to delete record');
    }
  };

  return (
    <Container className="my-5">
      <h1 className="text-center mb-4">Sentiment Analysis</h1>

      {error && <div className="alert alert-danger">{error}</div>}

      <Row>
        <Col md={6} className="mb-4">
          <Card className="shadow-sm">
            <Card.Body>
              <Card.Title>Text for Prediction:</Card.Title>
              <SentimentForm onSubmit={analyzeSentiment} loading={loading} />
            </Card.Body>
          </Card>
        </Col>

        <Col md={6} className="mb-4">
          <Card className="shadow-sm h-100">
            <Card.Body>
              <Card.Title>Result</Card.Title>
              <ResultDisplay result={result} />
            </Card.Body>
          </Card>
        </Col>
      </Row>

      <Row>
        <Col>
          <Card className="shadow-sm">
            <Card.Body>
              <Card.Title>Analysis History</Card.Title>
              <HistoryList history={history} onDelete={deleteRecord} />
            </Card.Body>
          </Card>
        </Col>
      </Row>
    </Container>
  );
}

export default App;
